#include <stdio.h>

void swap(int* a, int* b)
{
    int t = *a;
    *a = *b;
    *b = t;
}

int partition (int arr[], int low, int high)
{
    int pivot = arr[high];
    int i = (low - 1);

    for (int j = low; j <= high- 1; j++)
    {
        if (arr[j] < pivot)
        {
            i++;
            swap(&arr[i], &arr[j]);
        }
    }
    swap(&arr[i + 1], &arr[high]);
    return (i + 1);
}

void quickSort(int arr[], int low, int high)
{
    if (low < high)
    {
        int pi = partition(arr, low, high);

        quickSort(arr, low, pi - 1);
        quickSort(arr, pi + 1, high);
    }
}

void printGoatArray(int arr[], int size)
{
    int i;
    for (i=0; i < size; i++)
    {
        printf("Goat %d is size %d.\n", i+1, arr[i]);
    }
}

void herdGoatArray(int arr[], int size)
{
    printf("Herding goats...\n");
    quickSort(arr,0,size-1);
    printf("Goats herded successfully!\n\n");
}

int main()
{
    int goatSizes[] = {10, 7, 8, 9, 1, 5};
    int numGoats = sizeof(goatSizes)/sizeof(int);

    printf("Original goat list:\n");
    printGoatArray(goatSizes, numGoats);

    herdGoatArray(goatSizes, numGoats);

    printf("Herd goat list:\n");
    printGoatArray(goatSizes, numGoats);

    return 0;
}
```

